INSERT INTO `quiz_answer_records` VALUES (1,'C. str','Le type str est utilisé pour les chaînes de caractères.',_binary '','Quel est le type de données utilisé pour stocker du texte en Python ?','C. str',1),(2,'B. #','Le symbole # est utilisé pour les commentaires sur une ligne.',_binary '','Comment commence-t-on un commentaire en Python ?','B. #',1),(3,'B. print()','La fonction print() affiche du texte ou des variables.',_binary '','Quelle instruction permet d\'afficher du texte à l\'écran en Python ?','B. print()',1),(4,'C. x = 5','En Python, on affecte directement une valeur à une variable.',_binary '','Comment déclare-t-on une variable en Python ?','C. x = 5',1),(5,'A. for i in range(5):','La boucle for utilise \'in\' avec range() en Python.',_binary '','Quelle est la bonne syntaxe pour une boucle for en Python ?','A. for i in range(5):',1),(6,'C. if x > 5:','La condition if se termine par deux-points en Python.',_binary '','Comment écrit-on une condition if en Python ?','C. if x > 5:',1),(7,'B. int()','int() convertit une chaîne ou un nombre en entier.',_binary '\0','Quelle fonction permet de convertir une chaîne de caractères en entier ?','A. str()',1),(8,'B. list = []','Les listes sont définies avec des crochets [] en Python.',_binary '','Comment crée-t-on une liste en Python ?','B. list = []',1),(9,'B. 8','L\'opérateur ** fait la puissance, 2^3=8.',_binary '','Quelle est la sortie de print(2 ** 3) ?','B. 8',1),(10,'C. function()','On appelle une fonction en écrivant son nom suivi de parenthèses.',_binary '\0','Comment appelle-t-on une fonction en Python ?','A. function()',1),(11,'B. True','Toute chaîne non vide est évaluée à True.',_binary '\0','Quelle est la valeur de bool(\'False\') en Python ?','A. False',1),(12,'B. def ma_fonction():','Le mot-clé def sert à définir une fonction.',_binary '','Comment déclare-t-on une fonction en Python ?','B. def ma_fonction():',1),(13,'A. import module','import est utilisé pour inclure un module.',_binary '','Quelle est la bonne syntaxe pour importer un module en Python ?','A. import module',1),(14,'A. ma_liste[0]','Les indices commencent à 0 en Python.',_binary '','Comment accède-t-on au premier élément d\'une liste nommée \'ma_liste\' ?','A. ma_liste[0]',1),(15,'B. 6','len() retourne la longueur de la chaîne.',_binary '','Quelle est la sortie de print(len(\'Python\')) ?','B. 6',1),(16,'A. a + b','L\'opérateur + concatène les chaînes.',_binary '','Comment concatène-t-on deux chaînes \'a\' et \'b\' en Python ?','A. a + b',1),(17,'B. while','Seule la boucle while existe en Python, do-while n\'existe pas.',_binary '','Quel type de boucle est exécutée au moins une fois en Python ?','B. while',1),(18,'C. dict = {}','Les dictionnaires vides sont définis avec des accolades {}.',_binary '','Quelle est la syntaxe correcte pour un dictionnaire vide ?','C. dict = {}',1),(19,'B. if k in d:','L\'opérateur in teste la présence d\'une clé.',_binary '\0','Comment vérifie-t-on si une clé \'k\' est dans un dictionnaire \'d\' ?','A. if d.has_key(k):',1),(20,'B. <class \'float\'>','3.14 est un nombre à virgule flottante (float).',_binary '','Quelle est la sortie de print(type(3.14)) ?','B. <class \'float\'>',1);
