INSERT INTO `videos` VALUES (1,1,'Dans cette vidéo, vous comprendrez : \n- Qu\'est-ce que le langage python ? \n- Pourquoi devriez-vous apprendre Python?\n- Quels sont les utilisations de python ?\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/\n—————————————————————————————————— \n? Musiques :\nSunray valley by Scandinavianz https://soundcloud.com/scandinavianz\nFredji - Blue Sky by Vlog No Copyright Music https://youtu.be/Hf6vHY0lQTI',1,'https://i.ytimg.com/vi/YFfWOZkJ8i0/hqdefault.jpg','Python : qu\'est-ce que c\'est, pourquoi devriez-vous l\'apprendre et quels sont ses utilisations?','https://www.youtube.com/watch?v=YFfWOZkJ8i0'),(2,1,'Dans cette vidéo, vous découvrirez comment télécharger et installer Python et PyCharm sur Windows ?. Aussi comment exécuter votre premier programme Python.\n\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',2,'https://i.ytimg.com/vi/fpJjInuCSI8/hqdefault.jpg','Python #1 : Comment télécharger et installer Python et PyCharm ?','https://www.youtube.com/watch?v=fpJjInuCSI8'),(3,1,'Dans cette vidéo, vous comprendrez comment déclarer, affecter et utiliser des variables dans le langage Python.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',3,'https://i.ytimg.com/vi/rxoZW9uwP4E/hqdefault.jpg','Python #2 : Les variables : déclaration, affectation et utilisation','https://www.youtube.com/watch?v=rxoZW9uwP4E'),(4,1,'Dans cette vidéo, vous comprendrez comment utiliser :\n- La fonction print() pour afficher un message ou la valeur d\'une variable,\n- La fonction input() qui permet de demander à l\'utilisateur de fournir des informations.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nWLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',4,'https://i.ytimg.com/vi/Ue97Nvguvpk/hqdefault.jpg','Python #3 : print( ) et input( )','https://www.youtube.com/watch?v=Ue97Nvguvpk'),(5,1,'Dans cette vidéo, vous comprendrez comment utiliser \n- Les expressions arithmétique ( + , - , * , / , // , % , ** )\n- Les expressions de comparaisons \n- Les expressions logiques ( and , or , not )\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/\n—————————————————————————————————— \n? Musiques :\nFredji - Blue Sky by Vlog No Copyright Music https://youtu.be/Hf6vHY0lQTI',5,'https://i.ytimg.com/vi/r6E6QJ4bbs4/hqdefault.jpg','Python #4 : Expressions arithmétiques, expressions de comparaisons et expressions logiques','https://www.youtube.com/watch?v=r6E6QJ4bbs4'),(6,1,'Dans cette vidéo, vous comprendrez : \n- La différence entre les structures séquentielles et les structures conditionnelles\n- Comment utiliser la structure conditionnelle simple (un choix) : if ... : ...\n- Comment utiliser la structure conditionnelle alternative (deux choix) : if ...: ... else : ...\n- Comment utiliser la structure conditionnelle à choix multiple : if .... : .... elif ... : .... else : ...\n- Comment la structure ternaire pour simplifier la syntaxe de la structure conditionnelle\n\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/\n—————————————————————————————————— \n? Musiques : \nMBB - Bora Bora by Vlog No Copyright Music https://youtu.be/53ZjQWNfBcI',6,'https://i.ytimg.com/vi/_2mUZ1df8Bk/hqdefault.jpg','Python #5 : Structures conditionnelles : if .... : .... elif ... : .... else : ...','https://www.youtube.com/watch?v=_2mUZ1df8Bk'),(7,1,'Dans cette vidéo, vous comprendrez :\n- Le rôle des instructions répétitives\n- Comment utiliser la boucle for\n- Comment créer des séquences avec la fonction range()\n- Comment utiliser les boucles imbriquées\n- Plusieures exemples et exercices d’application\n\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',7,'https://i.ytimg.com/vi/mLWhYXPBWz4/hqdefault.jpg','Python #6 : Structures répétitives : la boucle for, la fonction range(), et les boucles imbriquées','https://www.youtube.com/watch?v=mLWhYXPBWz4'),(8,1,'Dans cette vidéo, vous comprendrez comment utiliser la boucle while qui permet de répéter un bloc d\'instructions tant qu\'une condition est vraie.\n\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',8,'https://i.ytimg.com/vi/V40UPbhlG_E/hqdefault.jpg','Python #7 : Structures répétitives : la boucle while','https://www.youtube.com/watch?v=V40UPbhlG_E'),(9,1,'Dans cette vidéo, vous comprendrez les deux instructions :\nL\'instruction break permet d\'arrêter le déroulement d\'une boucle, et de passer à l\'instruction qui suit cette boucle.\nL\'instruction continue permet d\'ignorer l\'itération actuelle de la boucle et de passer à l\'itération suivante.\n\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',9,'https://i.ytimg.com/vi/JXk_XtuP3-E/hqdefault.jpg','Python #8 : Structures répétitives : break et continue','https://www.youtube.com/watch?v=JXk_XtuP3-E'),(10,1,'Dans cette vidéo, vous comprendrez :\n- Qu\'est ce qu’une fonction ?\n- Comment définir une fonction dans langage Python,\n- Comment appeler une fonction dans langage Python.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/\n—————————————————————————————————— \n? Musiques :\nMBB - Bora Bora by Vlog No Copyright Music https://youtu.be/53ZjQWNfBcI',10,'https://i.ytimg.com/vi/XKUqUzZYpeM/hqdefault.jpg','Python #9 : Les fonctions : Qu\'est ce qu’une fonction et comment définir et appeler une fonction','https://www.youtube.com/watch?v=XKUqUzZYpeM'),(11,1,'Dans cette vidéo, vous comprendrez :\nQu\'est-ce qu\'une variable locale et comment l\'utiliser,\nQu\'est-ce qu\'une variable globale et comment l\'utiliser,\nLe rôle de mot-clé global.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/\n—————————————————————————————————— \n? Musiques :\nSunray valley by Scandinavianz https://soundcloud.com/scandinavianz',11,'https://i.ytimg.com/vi/1CdGDF11v_U/hqdefault.jpg','Python #10 : Les variables locales et les variables globales','https://www.youtube.com/watch?v=1CdGDF11v_U'),(12,1,'Dans cette vidéo, vous comprendrez le rôle et comment utiliser les arguments requis, par défaut et avec des étiquettes.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/\n—————————————————————————————————— \n? Musiques :\nCampfire by Roa https://soundcloud.com/roa_music1031 - Stream: http://bit.ly/al-campfire',12,'https://i.ytimg.com/vi/84_O6arLmIM/hqdefault.jpg','Python #11 : Type des arguments : requis, par défaut et avec étiquettes (mot-clé)','https://www.youtube.com/watch?v=84_O6arLmIM'),(13,1,'Dans cette vidéo, vous comprendrez :\n- L\'intérêt d\'utiliser les modules\n- Comment créer un module\n- Comment importer un module\n- L\'intérêt et comment utiliser les packages\n- Comment utiliser les modules standards: math, random, statistics, datetime, webbrowser, ..\n- Comment télécharger et utiliser un module avec PyCharm\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/\n—————————————————————————————————— \n? Musiques :\nFredji - Blue Sky by Vlog No Copyright Music https://youtu.be/Hf6vHY0lQTI',13,'https://i.ytimg.com/vi/mOIpeD0IqrU/hqdefault.jpg','Python #12 : Modules et Packages','https://www.youtube.com/watch?v=mOIpeD0IqrU'),(14,1,'Dans cette vidéo, vous comprendrez : \n- Qu\'est-ce qu\'une liste Python ?\n- Les caractéristiques d\'une liste Python ?\n- Comment créer une liste en python ?\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',14,'https://i.ytimg.com/vi/ODUU-R-IdmI/hqdefault.jpg','Python 13 : Qu\'est-ce qu\'une liste Python ? et comment la créer ?','https://www.youtube.com/watch?v=ODUU-R-IdmI'),(15,1,'Dans cette vidéo, vous comprendrez comment accéder aux éléments d\'une liste soit avec la méthode d\'indexation ou soit avec la méthode de découpage (slicing). Nous travaillerons également sur quatre exercices d\'application afin de mieux maîtriser l\'utilisation de ces deux techniques.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',15,'https://i.ytimg.com/vi/trcqhLpazl0/hqdefault.jpg','Python 14 : Accès aux éléments d\'une liste avec l\'indexation et le découpage (Slicing)','https://www.youtube.com/watch?v=trcqhLpazl0'),(16,1,'Dans cette vidéo, vous comprendrez comment utiliser : \n- L\'opérateur + pour concaténer deux ou plusieurs listes.\n- L\'opérateur * pour multiplier une liste n fois.\n- Les opérateurs de comparaison (==, !=, ...) pour comparer deux listes\nVous comprendrez également à effectuer l\'affectation multiple des éléments d\'une liste.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',16,'https://i.ytimg.com/vi/84F5LJYlwNA/hqdefault.jpg','Python 15 : Opérateurs sur les listes et affectation multiple','https://www.youtube.com/watch?v=84F5LJYlwNA'),(17,1,'Dans cette vidéo, vous découvrirez un total de 18 fonctions et méthodes les plus utilisées sur les listes. Plus précisément :\n- Création : list (),\n- Ajout : append(), insert(), extend(),  \n- Suppression : remove(), pop(), clear(), del\n- Opérations : len(), sum(), max(), min(), min(), min(), reverse(), sort(), sorted(),\n- Recherche : index(),\n- Duplication : copy(),\nPour chacune des méthodes et fonctions, vous découvrirez son intérêt et son objectif. Ensuite, à l\'aide de plusieurs exemples d\'application, vous maîtriserez sa syntaxe.\nEn plus de tout cela, nous travaillerons sur 4 exercices, afin de mieux comprendre et savoir appliquer les méthodes et fonctions sur les listes.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.fac',17,'https://i.ytimg.com/vi/7c7n3O5ti6I/hqdefault.jpg','Python 16 : Méthodes et fonctions de liste : append(), pop(), sort(), index(), copy(), len(), ...','https://www.youtube.com/watch?v=7c7n3O5ti6I'),(18,1,'Dans cette vidéo, vous comprendrez comment utiliser l\'opérateur in ou not in pour vérifier si un élément existe ou non dans une liste.\nEnsuite, vous découvrirez toutes les techniques qui permettent de parcourir les éléments d\'une liste, que ce soit avec la boucle for, avec la boucle for et la fonction range, la boucle for avec la fonction enumerate ou la boucle for avec la fonction zip. Vous verrez pour chaque technique la syntaxe d\'utilisation et un exemple d\'application.\nEn plus de tout cela, nous travaillerons sur 4 exercices, afin de mieux comprendre et savoir utiliser les différentes boucles pour parcourir les éléments des listes.\n\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: ht',18,'https://i.ytimg.com/vi/Sovw64eHe6o/hqdefault.jpg','Python 17 : Parcourir une liste avec for, range, enumerate et zip - Les opérateurs in et not in','https://www.youtube.com/watch?v=Sovw64eHe6o'),(19,1,'Dans cette vidéo, vous aller maitrise l\'utilisation des listes imbriquées ou des listes à 2D en travaillant sur les parties suivantes : vous allez découvrir d\'abord ce qu\'est une liste imbriquée, puis vous allez voir comment créer une liste imbriquée, puis vous aller comprendre comment accéder aux éléments d\'une liste imbriquée, puis vous aller comprendre comment utiliser les boucles pour parcourir les éléments d\'une liste imbriquée. Dans la dernière partie vous allez découvrir toutes les méthodes et fonctions que l\'on peut utiliser sur les listes imbriquées.\nEn plus de tout cela, nous allons travailler sur 2 exercices d\'application, afin de mieux comprendre et savoir utiliser les listes imbriquées ou 2D.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFa',19,'https://i.ytimg.com/vi/c68iWBZg9v0/hqdefault.jpg','Python 18 : Listes imbriquées (Listes 2D)','https://www.youtube.com/watch?v=c68iWBZg9v0'),(20,1,'Dans cette vidéo, vous découvrirez les fondamentaux des tuples en Python. Nous examinerons ce que sont les tuples, en quoi ils diffèrent des listes, et les particularités qui les rendent uniques. Vous apprendrez aussi des méthodes simples pour créer vos propres tuples. \n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',20,'https://i.ytimg.com/vi/0R0oJHnbFYk/hqdefault.jpg','Python 19 : Comprendre et Créer des Tuples en Python','https://www.youtube.com/watch?v=0R0oJHnbFYk'),(21,1,'Dans cette vidéo, vous découvrirez comment utiliser l\'indexation et le découpage pour accéder et manipuler les éléments des tuples en Python. La vidéo fournit des explications détaillées sur ces deux techniques clés, complétées par des exercices pratiques pour consolider votre apprentissage. \n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',21,'https://i.ytimg.com/vi/Stzs5gdoyls/hqdefault.jpg','Python 20 : Accès aux éléments d\'un tuple avec l\'indexation et le découpage (Slicing)','https://www.youtube.com/watch?v=Stzs5gdoyls'),(22,1,'Dans cette vidéo, vous apprendrez à manipuler efficacement les tuples en Python en utilisant divers opérateurs et techniques d\'affectation. Vous découvrirez comment concaténer deux ou plusieurs tuples avec l\'opérateur +, comment multiplier un tuple par un nombre spécifique de fois avec l\'opérateur *, et comment utiliser les opérateurs de comparaison comme == et != pour comparer deux tuples. De plus, la vidéo vous enseignera comment réaliser l\'affectation multiple des éléments d\'un tuple. \n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',22,'https://i.ytimg.com/vi/IME2a4mTG_c/hqdefault.jpg','Python 21 : Maîtriser les Opérateurs et l\'Affectation Multiple sur les Tuples en Python','https://www.youtube.com/watch?v=IME2a4mTG_c'),(23,1,'Dans cette vidéo, vous apprendrez à utiliser 9 fonctions et méthodes essentielles pour les tuples en Python, couvrant la création de tuples, diverses opérations comme len(), sum(), max(), min(), et sorted(), ainsi que la recherche d\'éléments avec index(). Chaque fonction et méthode est expliquée en détail avec des exemples pratiques et la vidéo inclut également 2 exercices pour renforcer la compréhension et l\'application de ces concepts. \n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',23,'https://i.ytimg.com/vi/g-IgI008nNE/hqdefault.jpg','Python 22 : Méthodes et fonctions de liste : len(), sorted(), index(), tuple(), range(), ...','https://www.youtube.com/watch?v=g-IgI008nNE'),(24,1,'Dans cette vidéo, nous explorons en détail comment parcourir des tuples en Python. Nous couvrirons l\'utilisation des opérateurs \'in\' et \'non in\', diverses approches de la boucle for, y compris l\'utilisation de range(), enumerate() et zip, pour améliorer vos compétences en programmation Python. I\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',24,'https://i.ytimg.com/vi/NeT-qv8lshw/hqdefault.jpg','Python 23 : Parcourir un tuple avec for, range, enumerate et zip - Les opérateurs in et not in','https://www.youtube.com/watch?v=NeT-qv8lshw'),(25,1,'Dans cette vidéo, vous aller maitrise l\'utilisation des tuples imbriqués ou des tuples à 2D en travaillant sur les parties suivantes : vous allez découvrir d\'abord ce qu\'est un tuple imbriqué, puis vous allez voir comment créer un tuple imbriqué, puis vous aller comprendre comment accéder aux éléments d\'une tuple imbriqué, puis vous aller comprendre comment utiliser les boucles pour parcourir les éléments d\'un tuple imbriqué. Dans la dernière partie vous allez découvrir toutes les méthodes et fonctions que l\'on peut utiliser sur les tuples imbriqués.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',25,'https://i.ytimg.com/vi/5swEepRYw8E/hqdefault.jpg','Python 24 : Tuples imbriqués (Tuples 2D)','https://www.youtube.com/watch?v=5swEepRYw8E'),(26,1,'Dans cette vidéo, nous explorerons ce qu\'est un ensemble, les propriétés uniques qui le définissent, les différentes méthodes pour le créer, ainsi que comment afficher et accéder à ses éléments.  \n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',26,'https://i.ytimg.com/vi/cZMwuBuVgbs/hqdefault.jpg','Python 25 : Comprendre et Créer des Ensembles en Python','https://www.youtube.com/watch?v=cZMwuBuVgbs'),(27,1,'Découvrez en détail les fonctions et méthodes essentielles pour manipuler les ensembles en Python dans cette vidéo tutorielle approfondie. Vous apprendrez à créer des ensembles avec les fonctions set() et range(), à enrichir vos ensembles grâce aux méthodes add() et update(), et à gérer efficacement la suppression d\'éléments avec pop(), clear(), remove() et discard(). Nous explorerons aussi comment utiliser des opérations telles que max(), min(), len(), et sum() pour analyser vos ensembles, et nous verrons comment dupliquer des ensembles à l\'aide de copy() et sécuriser leur immutabilité avec frozenset. \n  \n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',27,'https://i.ytimg.com/vi/Ztm5Ij65J34/hqdefault.jpg','Python 26 : Fonctions et Méthodes des Ensembles : add(), pop(), discard(), frozenset(), len(), ...','https://www.youtube.com/watch?v=Ztm5Ij65J34'),(28,1,'Dans cette vidéo, nous allons explorer en profondeur les différents opérateurs disponibles pour manipuler les ensembles en Python. Vous apprendrez à maîtriser les opérations essentielles pour manipuler et comparer des ensembles de manière efficace.\nCe que vous allez découvrir : Union, Intersection, Différence, Différence Symétrique, Sous-ensemble, Sur-ensemble, Égalité et Disjonction.  \n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',28,'https://i.ytimg.com/vi/JafGF5NsooA/hqdefault.jpg','Python 27 : Opérateurs sur les Ensembles en Python : Union, Intersection, Différence, Égalité ...','https://www.youtube.com/watch?v=JafGF5NsooA'),(29,1,'Dans cette vidéo, nous plongeons dans les fondamentaux des ensembles en Python, en mettant l\'accent sur deux aspects cruciaux : l\'appartenance et le parcours.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',29,'https://i.ytimg.com/vi/1R4XJKD3iSQ/hqdefault.jpg','Python 28 : Comment Parcourir et Vérifier l\'Appartenance dans un Ensemble','https://www.youtube.com/watch?v=1R4XJKD3iSQ'),(30,1,'Dans cette vidéo, nous explorerons ce qu\'est un dictionnaire et les propriétés uniques qui le définissent.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.com/groups/devcademy\nSite Web: http://elbahihassan.com/',30,'https://i.ytimg.com/vi/EHbgSZnJ_vk/hqdefault.jpg','Python 29 : Comprendre les Dictionnaires en Python','https://www.youtube.com/watch?v=EHbgSZnJ_vk'),(31,1,'Dans cette vidéo, vous allez comprendre les différentes méthodes pour créer un dictionnaire en Python.\n———————————— \nPlaylists\nCours :  https://bit.ly/3hyErDY\nExercices corrigés en Python : https://bit.ly/3sdkB6s\n———————————— \nLinkedIn : http://linkedin.com/in/elbahihassan\nInstagram : https://www.instagram.com/hassan.el.bahi/\nFacebook page : https://www.facebook.com/elbahihassanPage\nFacebook groupe : https://www.facebook.